const raw = $input.first().json;
const body = raw.body || raw;

const message     = String(body.message || body.query || body.text || '').trim();
const business_id = String(body.business_id || '').trim();
const session_id  = String(body.session_id || Date.now()).trim();
const userAgent   = String(body.user_agent || body.userAgent || '').toLowerCase();
const ip          = String(body.ip || body.client_ip || '').trim();

if (!message)     return [{ json: { valid: false, error: 'Message is required' } }];
if (!business_id) return [{ json: { valid: false, error: 'business_id is required' } }];

const q = message.toLowerCase().trim();

// ════════════════════════════════════════════════════════════
// 🤖 BOT / FAKE QUERY DETECTION
// ════════════════════════════════════════════════════════════
let isFake     = false;
let fakeReason = null;
let fakeScore  = 0; // jitna zyada = utna zyada bot

// ── 1. Message bahut chota ya meaningless ───────────────────
if (message.length < 2) {
  isFake = true; fakeReason = 'too_short';
}

// ── 2. Sirf numbers/symbols — no real query ─────────────────
if (/^[\d\s\.\-\+\*\/\=\!\@\#\$\%\^&]+$/.test(message) && message.length < 8) {
  fakeScore += 30;
}

// ── 3. Repeated characters — asdasd, aaaa, 1234 ────────────
if (/(.)\1{3,}/.test(message) && message.length < 20) {
  fakeScore += 40; // "aaaaaa" or "111111"
}
if (/^(asdf|qwer|zxcv|test|abc|xyz|asd|hello|hi|hey|yo|ok|okay)/i.test(message)) {
  fakeScore += 20;
}

// ── Phone number? Never fake ────────────────────────────────
const hasPhone = /(\+92|0092|03\d{9}|\+\d{10,14})/.test(message);
if (hasPhone) {
  // Phone number = real human, skip ALL bot checks
  fakeScore = 0; isFake = false;
}

// ── 4. Known bot/spam patterns ──────────────────────────────────
const botPatterns = [
  /^(test|testing|check|ping|hello|hi there|hey|yo|ok|okay|lol|haha)$/i,
  /^(\d+)$/,              // sirf number like "123"
  /^[a-z]{1,2}$/i,        // single/double letter "a" "ab"
  /<script|javascript:|onclick|onerror|alert\(|eval\(/i,  // XSS
  /select\s+\*|drop\s+table|insert\s+into|union\s+select/i, // SQL injection
  /\b(viagra|casino|loan|crypto|bitcoin|invest now)\b/i,    // spam
];
for (const pat of botPatterns) {
  if (pat.test(message)) { fakeScore += 40; break; }
}

// ── 5. Bot user agents ───────────────────────────────────────
const botAgents = ['googlebot','bingbot','crawler','spider','scraper',
  'curl','wget','python-requests','postman','insomnia'];
if (botAgents.some(b => userAgent.includes(b))) {
  fakeScore += 50;
}

// ── 6. Bahut tez queries — same session mein 1 second se kam ─
// (session_id Unix timestamp hai)
// Agar session_id difference < 3 seconds = bot
// Note: yeh next level check hai, abhi flag karo
const tsNow = Date.now();
const tsSession = parseInt(session_id) || 0;
const ageSec = tsSession > 1000000000000 ? (tsNow - tsSession) / 1000 : 999;
if (ageSec < 2 && ageSec > 0) {
  fakeScore += 30; // query bahut tezi se aayi
}

// ── 7. Known test phrases (aap khud test kar rahi thi) ───────
const testPhrases = [
  /^(test|testing \d+|test query|check|ping)$/i,
  /^(hello|hi|hey|assalam|salam)$/i,   // sirf greeting, koi query nahi
];
for (const pat of testPhrases) {
  if (pat.test(message.trim())) { fakeScore += 15; }
}

// ── Final fake decision ──────────────────────────────────────
if (fakeScore >= 40) {
  isFake = true;
  fakeReason = fakeReason || `suspicious_score_${fakeScore}`;
}

// ── Flag but don't block — still answer, just don't save as lead
const isLikelyTest = fakeScore >= 20 && fakeScore < 40;

// ════════════════════════════════════════════════════════════
// 📞 CONTACT DETECTION
// ════════════════════════════════════════════════════════════
const phoneRegex = /(\+92|0092|03)\d{9,10}|03\d{2}[-\s]?\d{7}/;
const phoneMatch = message.match(phoneRegex);
const detectedPhone = phoneMatch ? phoneMatch[0].replace(/[\s-]/g,'') : null;

const namePatterns = [
  /(?:mera naam|my name is|naam hai|i am|main hun|میرا نام)\s+([a-zA-Z\u0600-\u06FF]{2,}\s*[a-zA-Z\u0600-\u06FF]{0,})/i,
  /^([A-Z][a-z]+\s+[A-Z][a-z]+)$/,
];
let detectedName = null;
for (const pat of namePatterns) {
  const m = message.match(pat);
  if (m && m[1]) { detectedName = m[1].trim(); break; }
}

const isContactSubmission = !!(detectedPhone || detectedName) &&
  (detectedPhone || q.includes('naam') || /^[a-zA-Z\s]{3,25}$/.test(message.trim()));

// ════════════════════════════════════════════════════════════
// 🎯 INTENT DETECTION
// ════════════════════════════════════════════════════════════
let intent = 'search';

if (isContactSubmission) {
  intent = 'contact_submission';
} else if (q.includes('sale') || q.includes('discount') || q.includes('offer') ||
    q.includes('sasta') || q.includes('cheap') || q.includes('saving')) {
  intent = 'sale';
} else if (q.includes('price') || q.includes('cost') || q.includes('rate') ||
           q.includes('قیمت') || q.includes('how much') || q.includes('kitna') ||
           q.includes('kitni') || q.includes('charges')) {
  intent = 'price';
} else if (q.includes('available') || q.includes('in stock') ||
           q.includes('milega') || q.includes('hai kya') ||
           q.includes('stock mein') || q.includes('dastiyab')) {
  intent = 'stock';
} else if (q.includes('categor') || q.includes('qisam')) {
  intent = 'category';
}

// ════════════════════════════════════════════════════════════
// 🔑 KEYWORD EXTRACTION
// ════════════════════════════════════════════════════════════
const stopWords = new Set([
  'what','is','the','price','of','do','you','have','can','i','get','a',
  'show','me','tell','about','kya','hai','hain','ka','ki','ke','mujhe',
  'batao','dikhao','sale','discount','stock','available','how','much',
  'any','your','all','and','mein','se','ko','aur','ya','milega','milegi',
  'chahiye','please','plz','bata','dena','dedo','karo','hoga','hogi',
  'konsa','konsi','konse','wala','wali','wale','per','bhi','toh','yeh',
  'woh','iss','unn','inn','tha','thi','the','hai','hain','hua','hui'
]);

const multiWordProducts = [
  'olive oil','coconut oil','mustard oil','almond oil','hair oil',
  'cooking oil','black seed','kalonji oil','fish oil',
  'honey salajeet','ashraf naturals','hamdard','qarshi','johar joshanda'
];

let keywords = [];
const qClean = q.replace(/[?!.,؟،]/g, ' ');
for (const mw of multiWordProducts) {
  if (qClean.includes(mw)) {
    keywords.push(mw.split(' ')[0]);
    const second = mw.split(' ')[1];
    if (second && second.length > 2) keywords.push(second);
  }
}
const singleWords = qClean.split(/\s+/).map(w=>w.trim())
  .filter(w => w.length > 2 && !stopWords.has(w));
for (const w of singleWords) {
  if (!keywords.some(k => k.includes(w) || w.includes(k))) keywords.push(w);
}
keywords = [...new Set(keywords)].slice(0, 5);

return [{
  json: {
    valid: true,
    message,
    business_id,
    session_id,
    intent,
    keywords,
    q,
    detectedPhone,
    detectedName,
    isContactSubmission,
    // Bot detection results
    isFake,
    isLikelyTest,
    fakeReason,
    fakeScore
  }
}];

const intent_data = $('Validate & Classify Intent').first().json;

const products = $input.all().map(item => item.json);

// Extract matched product names — ALWAYS before any early return
const matchedProductNames = products.map(p => p.name).filter(Boolean).join(', ');

if (products.length === 0) {
  return [{
    json: {
      ...intent_data,
      matchedProductNames,
      product_context: 'No products found matching the query.',
      product_count: 0
    }
  }];
}

function stripHtml(html) {
  return (html || '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]*>/g, '')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s\s+/g, ' ')
    .trim();
}

const formatted = products.map(p => {
  const cats = (p.categories || []).map(c => c.name || c).join(', ');
  let lines = [];

  lines.push(`PRODUCT: ${p.name}`);

  if (p.sale_price && parseFloat(p.sale_price) > 0 && parseFloat(p.sale_price) !== parseFloat(p.regular_price)) {
    const discount = p.regular_price && parseFloat(p.regular_price) > 0
      ? Math.round(((parseFloat(p.regular_price) - parseFloat(p.sale_price)) / parseFloat(p.regular_price)) * 100)
      : 0;
    lines.push(`Price: Rs.${p.sale_price} (ON SALE! Was Rs.${p.regular_price} — ${discount}% off)`);
  } else if (p.price) {
    lines.push(`Price: Rs.${p.price}`);
  }

  const stockLabel = p.stock_status === 'instock' ? 'In Stock' : 'Out of Stock';
  const qty = p.stock_quantity > 0 ? ` (${p.stock_quantity} units)` : '';
  lines.push(`Availability: ${stockLabel}${qty}`);

  if (cats) lines.push(`Category: ${cats}`);

  const shortDesc = stripHtml(p.short_description);
  if (shortDesc) lines.push(`Summary: ${shortDesc.substring(0, 400)}`);

  const longDesc = stripHtml(p.description);
  if (longDesc && longDesc !== shortDesc) {
    lines.push(`Details: ${longDesc.substring(0, 800)}`);
  }

  return lines.join('\n');
}).join('\n\n---\n\n');

return [{
  json: {
    ...intent_data,
    matchedProductNames,
    product_context: formatted,
    product_count: products.length
  }
}];

const openaiResp = $input.first().json;
const intentData = $('Validate & Classify Intent').first().json;
const formatData = $('Format Products for Claude').first().json;

let reply = '';
try {
  if (openaiResp.message && openaiResp.message.content) {
    reply = openaiResp.message.content;
  } else if (openaiResp.choices && openaiResp.choices[0]) {
    reply = openaiResp.choices[0].message?.content || '';
  } else if (openaiResp.text) {
    reply = openaiResp.text;
  } else if (openaiResp.content) {
    reply = openaiResp.content;
  } else {
    reply = 'Sorry, I could not generate an answer. Please try again.';
  }
} catch(e) {
  reply = 'Sorry, something went wrong. Please try again.';
}

const q = (intentData.message || '').toLowerCase();
const kwList = ['olive oil','pomace','mustard oil','mustard','coconut oil','coconut','almond oil',
  'almond','borges','italia','sasso','mundial','chia','til','honey','shehad','sidr',
  'qarshi','johar','joshanda','hamdard','herb','masala','hair oil','cooking oil','ghee'];
let detectedProduct = null;
for (const kw of kwList) { if (q.includes(kw)) { detectedProduct = kw; break; } }
if (!detectedProduct && intentData.keywords?.length > 0) detectedProduct = intentData.keywords[0];

// Contact info from Validate node
const detectedPhone = intentData.detectedPhone || null;
const detectedName  = intentData.detectedName  || null;
const isContactSubmission = intentData.isContactSubmission || false;

// If contact submitted — boost score
const contactBonus = detectedPhone ? 30 : 0;

return [{
  json: {
    success: true,
    reply,
    intent: intentData.intent,
    products_found: formatData.product_count || 0,
    session_id: intentData.session_id,
    detectedPhone,
    detectedName,
    isContactSubmission,
    contactBonus,
    searchLog: {
      business_id: intentData.business_id,
      query_text: intentData.message.substring(0, 500),
      detected_product: detectedProduct,
      detected_intent: intentData.intent,
      products_found: formatData.product_count || 0,
      session_id: intentData.session_id,
      created_at: new Date().toISOString()
    }
  }
}];

const scored = $('Score & Qualify Lead').first().json;
let raw;
try { raw = $input.first().json; } catch(e) { raw = {}; }
const biz = Array.isArray(raw) ? raw[0] : raw;
const chatId = biz?.telegram_chat_id || '6712600936';
return [{ json: { ...scored, telegram_chat_id: String(chatId) } }];

function cleanPhone(raw) {
  if (!raw) return { phone: null, waNumber: null, waLink: null };
  let phone = raw.replace(/[\s\-\.()]/g, '');
  if (phone.startsWith('+')) {
    const waNumber = phone.slice(1);
    return { phone: raw, waNumber, waLink: `https://wa.me/${waNumber}` };
  }
  if (/^03\d{9}$/.test(phone)) {
    const waNumber = '92' + phone.slice(1);
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }
  if (phone.startsWith('0092')) {
    const waNumber = phone.slice(2);
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }
  if (/^[1-9]\d{9,14}$/.test(phone)) {
    return { phone, waNumber: phone, waLink: `https://wa.me/${phone}` };
  }
  if (/^05\d{8}$/.test(phone)) {
    const waNumber = '971' + phone.slice(1);
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }
  if (/^07\d{9}$/.test(phone)) {
    const waNumber = '44' + phone.slice(1);
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }
  if (/^[2-9]\d{9}$/.test(phone)) {
    const waNumber = '1' + phone;
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }
  return { phone, waNumber: phone, waLink: `https://wa.me/${phone}` };
}

const d = $input.first().json;

// FIX: needsAlert false hone pe bhi telegramMsg set karo
// Taake Send Hot Lead Telegram node mein undefined na aaye
if (!d.needsAlert) {
  return [{ json: { ...d, alertSkipped: true, telegramMsg: null } }];
}

const { phone, waNumber, waLink } = cleanPhone(d.phone);
const emoji = d.phone ? '🔴🔥' : (d.priority === 'Hot' ? '🔴' : '🟡');

let msg = `${emoji} *New Lead — SK Natural!*\n\n`;
if (d.name)    msg += `👤 *Interested in:* ${d.name}\n`;
if (d.phone)   msg += `📞 *Phone:* ${d.phone}\n`;
if (waNumber)  msg += `🌍 *WhatsApp:* +${waNumber}\n`;
msg += `🛍️ *Product:* ${d.service || d.products_interested || 'General'}\n`;
msg += `💬 *Query:* "${(d.query_text || '').substring(0,100)}"\n`;
msg += `\n📊 *Score:* ${d.score}/100 — ${d.priority}\n`;
msg += `✅ *Action:* ${d.recommended_action}\n`;
if (waLink) {
  msg += `\n👇 *EK CLICK MEIN WHATSAPP KARO:*\n`;
  msg += `${waLink}\n`;
}
msg += `\n_BizFlow AI — ${new Date().toLocaleTimeString('en-PK')}_`;

return [{ json: { ...d, telegramMsg: msg, waLink } }];

const data = $('Extract OpenAI Reply').first().json;
const intentData = $('Validate & Classify Intent').first().json;

// ── Fake/Bot check — agar fake hai to save mat karo ──────────
const isFake       = intentData.isFake || false;
const isLikelyTest = intentData.isLikelyTest || false;
const fakeReason   = intentData.fakeReason || null;
const fakeScore_v  = intentData.fakeScore || 0;

if (isFake) {
  // Workflow continue karega — chatbot answer dega
  // Lekin CRM mein save NAHI hoga (score -999 = skip signal)
  return [{
    json: {
      business_id: intentData.business_id,
      name: 'FAKE/BOT — Skipped',
      service: 'bot',
      priority: 'Cold',
      score: -1,          // ← -1 = save mat karo
      signals: `fake,${fakeReason}`,
      ai_summary: `Bot/fake query detected. Reason: ${fakeReason}. Fake score: ${fakeScore_v}`,
      recommended_action: 'Skip — automated or test query',
      estimated_value: 0,
      query_text: intentData.message,
      session_id: intentData.session_id,
      products_found: data.products_found || 0,
      intent: 'fake',
      created_at: new Date().toISOString(),
      searchLog: data.searchLog,
      reply: data.reply,
      success: data.success,
      needsAlert: false,
      skipSave: true       // ← CRM save skip karo
    }
  }];
}

const intent      = data.intent || 'search';
const message     = intentData.message || '';
const keywords    = intentData.keywords || [];
const productsFound = data.products_found || 0;
const sessionId   = data.session_id || '';
const businessId  = intentData.business_id || '';
const detectedPhone = data.detectedPhone || null;
const detectedName  = data.detectedName  || null;
const q = message.toLowerCase();

let score = 0;
let signals = [];

// ── BASE SCORE — har query ki minimum value ──────────────────
// Koi bhi chatbot par aaya = already interested
score += 20;
signals.push('chatbot_visitor');

// ── CONTACT INFO ─────────────────────────────────────────────
if (detectedPhone) { score += 40; signals.push('phone_shared'); }
if (detectedName)  { score += 10; signals.push('name_shared'); }

// ── INTENT SCORING ───────────────────────────────────────────
// Price poochna = buying intent
if (intent === 'price') {
  score += 25;
  signals.push('price_inquiry');
}
// Stock check = ready to buy
else if (intent === 'stock') {
  score += 20;
  signals.push('stock_check');
}
// Sale/discount = price sensitive buyer
else if (intent === 'sale') {
  score += 15;
  signals.push('sale_interest');
}
// contact_submission handled separately
else if (intent === 'contact_submission') {
  score += 30;
  signals.push('contact_submission');
}
// Category browse = early stage
else {
  score += 5;
  signals.push('product_browse');
}

// ── KEYWORD QUALITY — kya specific product maanga? ──────────
// Specific product name = serious shopper
if (keywords.length >= 1) { score += 10; signals.push('specific_product'); }
if (keywords.length >= 2) { score += 5;  signals.push('multi_keyword'); }

// ── PRODUCTS FOUND — product actually available hai ─────────
if (productsFound >= 1) { score += 10; signals.push('product_available'); }
if (productsFound >= 3) { score += 5;  signals.push('multiple_options'); }

// ── HIGH INTENT SIGNALS ──────────────────────────────────────
// Bulk/wholesale = B2B opportunity
if (/bulk|wholesale|dozen|carton|box|quantity|gross|thok/.test(q)) {
  score += 20;
  signals.push('bulk_inquiry');
}
// Urgency = ready to buy now
if (/urgent|today|asap|jaldi|abhi|chahiye|chaiye|chahiye|abhi chahiye/.test(q)) {
  score += 15;
  signals.push('urgency');
}
// Price comparison = decision stage
if (/compare|vs|better|best|recommend|konsa|konsi|suggest/.test(q)) {
  score += 10;
  signals.push('comparison');
}
// Order related words
if (/order|mangwana|book|deliver|shipping|send karo/.test(q)) {
  score += 15;
  signals.push('order_intent');
}

score = Math.min(score, 100);

// ── PRIORITY ─────────────────────────────────────────────────
let priority = 'Cold';
if      (score >= 70) priority = 'Hot';
else if (score >= 40) priority = 'Warm';

// ── LEAD NAME ────────────────────────────────────────────────
const detectedProduct = data.searchLog?.detected_product || keywords[0] || null;

let oppName;
if (detectedName && detectedProduct)
  oppName = `${detectedName} — ${detectedProduct.charAt(0).toUpperCase()+detectedProduct.slice(1)}`;
else if (detectedName)
  oppName = `${detectedName} — Chatbot Inquiry`;
else if (detectedProduct)
  oppName = `Chatbot: ${detectedProduct.charAt(0).toUpperCase()+detectedProduct.slice(1)}`;
else
  oppName = `Chatbot: ${intent.charAt(0).toUpperCase()+intent.slice(1)} Inquiry`;

// ── ESTIMATED VALUE ──────────────────────────────────────────
let estValue = 1000;
if (intent === 'price')  estValue = 2500;
if (intent === 'stock')  estValue = 2000;
if (signals.includes('bulk_inquiry')) estValue = 8000;
if (detectedPhone) estValue = estValue * 1.5;

// ── SUMMARY ──────────────────────────────────────────────────
const aiSummary = `Customer asked: "${message.substring(0,200)}". Intent: ${intent}. Products matched: ${productsFound}. Signals: ${signals.join(', ')}.${detectedPhone?' Phone: '+detectedPhone:''}${detectedName?' Name: '+detectedName:''}`;

let action;
if (detectedPhone)         action = '📞 CALL NOW — customer ne phone number diya!';
else if (priority==='Hot') action = '⚡ Call within 2 hours — high purchase intent';
else if (priority==='Warm')action = '💬 Send follow-up message today';
else                       action = '👀 Monitor — early stage interest';

return [{
  json: {
    business_id: businessId,
    name: oppName,
    service: detectedProduct || intent,
    phone: detectedPhone,
    source: 'chatbot',
    status: 'new',
    priority,
    score,
    signals: signals.join(','),
    ai_summary: aiSummary,
    recommended_action: action,
    estimated_value: Math.round(estValue),
    query_text: message.substring(0, 500),
    session_id: sessionId,
    products_found: productsFound,
    intent,
    created_at: new Date().toISOString(),
    searchLog: data.searchLog,
    reply: data.reply,
    success: data.success,
    needsAlert: priority === 'Hot' || !!detectedPhone
  }
}];

const intentData = $input.first().json;
const businessId = intentData.business_id || '';
const detectedPhone = intentData.detectedPhone || '';
const detectedName  = intentData.detectedName  || '';
const sessionId     = intentData.session_id || '';
const message       = intentData.message || '';

// Thank you reply
let reply;
if (detectedName) {
  reply = `Shukriya ${detectedName} ji! 🙏 Hamare team member aapko jald hi contact karenge. Kya aur kuch poochna chahte hain?`;
} else {
  reply = `Shukriya! 🙏 Aapka number (${detectedPhone}) note ho gaya. Hamare team member aapko jald hi WhatsApp karenge. Kya aur kuch poochna chahte hain?`;
}

// High score since phone shared
const score = detectedPhone ? 85 : 60;
const priority = score >= 70 ? 'Hot' : 'Warm';

const oppName = detectedName 
  ? `${detectedName} — Phone Shared`
  : `Contact Submission — ${detectedPhone}`;

const aiSummary = `Customer ne phone number share kiya: ${detectedPhone}. ${detectedName ? 'Naam: '+detectedName+'.' : ''} Direct contact available.`;

return [{
  json: {
    business_id: businessId,
    name: oppName,
    service: 'direct_contact',
    phone: detectedPhone,
    source: 'chatbot',
    status: 'new',
    priority,
    score,
    signals: 'phone_shared,contact_submission',
    ai_summary: aiSummary,
    recommended_action: 'CALL NOW — customer ne phone number diya!',
    estimated_value: 3000,
    query_text: message.substring(0, 500),
    session_id: sessionId,
    products_found: 0,
    intent: 'contact_submission',
    created_at: new Date().toISOString(),
    reply,
    success: true,
    needsAlert: true,
    searchLog: {
      business_id: businessId,
      query_text: message.substring(0, 500),
      detected_product: null,
      detected_intent: 'contact_submission',
      products_found: 0,
      session_id: sessionId,
      created_at: new Date().toISOString()
    }
  }
}];

function cleanPhone(raw) {
  if (!raw) return { phone: null, waNumber: null, waLink: null };

  // Remove spaces, dashes, dots, brackets
  let phone = raw.replace(/[\s\-\.()]/g, '');

  // Already has + — remove it for wa.me
  if (phone.startsWith('+')) {
    const waNumber = phone.slice(1);
    return { phone: raw, waNumber, waLink: `https://wa.me/${waNumber}` };
  }

  // Pakistan: 03xxxxxxxxx → 923xxxxxxxxx
  if (/^03\d{9}$/.test(phone)) {
    const waNumber = '92' + phone.slice(1);
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }

  // Pakistan with 0092: 00923xxxxxxxxx
  if (phone.startsWith('0092')) {
    const waNumber = phone.slice(2);
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }

  // Already has country code (10-15 digits, no leading 0)
  // e.g. 923001234567, 447911123456, 12025551234
  if (/^[1-9]\d{9,14}$/.test(phone)) {
    return { phone, waNumber: phone, waLink: `https://wa.me/${phone}` };
  }

  // UAE: 05xxxxxxxx → 9715xxxxxxxx
  if (/^05\d{8}$/.test(phone)) {
    const waNumber = '971' + phone.slice(1);
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }

  // UK: 07xxxxxxxxx → 447xxxxxxxxx
  if (/^07\d{9}$/.test(phone)) {
    const waNumber = '44' + phone.slice(1);
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }

  // US/Canada: 10 digits starting with area code
  if (/^[2-9]\d{9}$/.test(phone)) {
    const waNumber = '1' + phone;
    return { phone, waNumber, waLink: `https://wa.me/${waNumber}` };
  }

  // Fallback — use as-is
  return { phone, waNumber: phone, waLink: `https://wa.me/${phone}` };
}

